package org.apache.commons.compress.archivers.tar;

import org.junit.runner.RunWith;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.compress.archivers.tar.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.compress.archivers.tar.steps;

import org.apache.commons.compress.archivers.tar.TarUtils;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import static org.junit.Assert.assertEquals;

public class StepDefs {

    private byte[] buffer;
    private long parsedValue;
    private Exception exception;

    @Given("a byte buffer of length 12 populated with the ASCII string {string}")
    public void a_byte_buffer_of_length_12_populated_with_the_ASCII_string(String asciiString) {
        buffer = new byte[12];
        byte[] inputBytes = asciiString.getBytes();
        System.arraycopy(inputBytes, 0, buffer, 0, Math.min(inputBytes.length, buffer.length));
    }

    @When("TarUtils.parseOctal is executed on this buffer")
    public void tarutils_parseoctal_is_executed_on_this_buffer() {
        try {
            parsedValue = TarUtils.parseOctal(buffer, 0, buffer.length);
        } catch (Exception e) {
            this.exception = e;
        }
    }

    @Then("the parsed value should be {long}")
    public void the_parsed_value_should_be(long expectedValue) {
        assertEquals("Parsed value should match expected value", expectedValue, parsedValue);
    }
}
